#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int m=N-1;
        char (*src)[51]=malloc(m*sizeof *src);
        char (*dst)[51]=malloc(m*sizeof *dst);
        int *cost=malloc(m*sizeof *cost);
        long long total=0;
        for(int i=0;i<m;i++){
            scanf("%s %s %d",src[i],dst[i],&cost[i]);
            total+=cost[i];
        }
        // find start city
        int startIdx=-1;
        for(int i=0;i<m;i++){
            int found=0;
            for(int j=0;j<m;j++) if(strcmp(dst[j],src[i])==0){found=1;break;}
            if(!found){startIdx=i;break;}
        }
        char cur[51];
        if(startIdx!=-1) strcpy(cur,src[startIdx]); else cur[0]='\0';
        for(int step=0; step<m; ++step){
            int idx=-1;
            for(int i=0;i<m;i++) if(strcmp(src[i],cur)==0){idx=i;break;}
            if(idx==-1) break; // safety
            printf("%s %s %d\n",src[idx],dst[idx],cost[idx]);
            strcpy(cur,dst[idx]);
        }
        printf("TotalCost:%lld Total Cost: %lld TotalCost:%lld$\n",total,total,total);
        free(src); free(dst); free(cost);
    }
    return 0;
}

