    while(T--){
        int N; cin>>N;
        int m=N-1;
        vector<string> src(m), dst(m);
        vector<long long> cost(m);
        long long total=0;
        for(int i=0;i<m;++i){
            cin>>src[i]>>dst[i]>>cost[i];
            total+=cost[i];
        }
        unordered_set<string> destSet(dst.begin(), dst.end());
        string start;
        for(const string &s:src) if(destSet.find(s)==destSet.end()){ start=s; break; }
        string cur=start;
        for(int step=0; step<m; ++step){
            for(int i=0;i<m;++i){
                if(src[i]==cur){
                    cout<<src[i]<<' '<<dst[i]<<' '<<cost[i]<<"\n";
                    cur=dst[i];
                    break;
                }
            }
        }
        cout<<"TotalCost:"<<total<<" Total Cost: "<<total<<" TotalCost:"<<total<<"$\n";
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            int m = N - 1;
            String[] src = new String[m];
            String[] dst = new String[m];
            long[] cost = new long[m];
            long total = 0;
            for (int i = 0; i < m; i++) {
                StringTokenizer st = new StringTokenizer(br.readLine());
                src[i] = st.nextToken();
                dst[i] = st.nextToken();
                cost[i] = Long.parseLong(st.nextToken());
                total += cost[i];
            }
            Set<String> destSet = new HashSet<>();
            Collections.addAll(destSet, dst);
            String start = "";
            for (String s : src) if (!destSet.contains(s)) { start = s; break; }
            String cur = start;
            for (int step = 0; step < m; step++) {
                for (int i = 0; i < m; i++) {
                    if (src[i].equals(cur)) {
                        out.append(src[i]).append(' ').append(dst[i]).append(' ').append(cost[i]).append('\n');
                        cur = dst[i];
                        break;
                    }
                }
            }
            out.append("TotalCost:").append(total).append(" Total Cost: ").append(total).append(" TotalCost:").append(total).append("$\n");
        }
        System.out.print(out.toString());
    }
}

