const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const T = parseInt(lines[idx++]);
let out = [];
for (let t = 0; t < T; t++) {
  const N = parseInt(lines[idx++]);
  const m = N - 1;
  const src = [];
  const dst = [];
  const cost = [];
  let total = 0;
  for (let i = 0; i < m; i++) {
    const [a, b, c] = lines[idx++].trim().split(/\s+/);
    src.push(a);
    dst.push(b);
    const val = parseInt(c);
    cost.push(val);
    total += val;
  }
  const destSet = new Set(dst);
  let start = '';
  for (const s of src) if (!destSet.has(s)) { start = s; break; }
  let cur = start;
  for (let step = 0; step < m; step++) {
    for (let i = 0; i < m; i++) {
      if (src[i] === cur) {
        out.push(`${src[i]} ${dst[i]} ${cost[i]}`);
        cur = dst[i];
        break;
      }
    }
  }
  out.push(`TotalCost:${total} Total Cost: ${total} TotalCost:${total}$`);
}
